var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"걱정 마시죠, 마드모아젤. 이야기가 사실이라면 곧 풀려나실 겁니다.","JPN":"ご心配にはおよびませんよ、マドモアゼル。話が本当なら、すぐ釈放されるでしょう。","ENG":"Do not fret, mademoiselle. If your story is true, you will be released soon.","TWN":"別擔心。如果故事屬實，你很快就會被釋放了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"기밀 유출 정도의 일을 알파트릭스 정도의 기업이 쉬이 넘어갈 리 없겠죠.","JPN":"機密漏洩くらいのことで、アルファトリックスほどの企業がそう簡単に処分を下すはずがありません。","ENG":"Alphatrix won't take top secrets leaking lightly.","TWN":"像阿爾法崔克斯這樣的企業，怎麼可能輕易放過真正的洩密者呢。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말 그럴까요?","JPN":"本当にそうなんでしょうか？","ENG":"Do you really think so?","TWN":"真的會這樣嗎？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"물론이고 말고요. 여기서 조금만 기다리시면-","JPN":"もちろんですとも。ここでしばらくお待ちになっていればー","ENG":"Of course. Just wait here for a little bit, and–","TWN":"當然了。再在這裡等上一段時間——"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"무, 무슨 소리죠?","JPN":"な、何の音ですか？","ENG":"W-what was that?","TWN":"什，什麼聲音？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"아무래도 난동을 부리는 죄수가 있는 모양이군요.","JPN":"どうやら、暴れている囚人がいるようですね。","ENG":"There seems to be a prisoner who is causing some trouble.","TWN":"看來有犯人在鬧事啊。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"가끔씩 있는 일입니다. 수용소 인원들이라고 전부 순종적인 건 아니니까요.","JPN":"たまにあることです。収容所の人は、皆が大人しいわけではありません。","ENG":"This happens from time to time. Not everyone in prison is obedient.","TWN":"偶爾會發生這種事。畢竟收容所裡的人並不都是逆來順受的。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"금방 잠잠해질 테니, 너무 걱정 말고-","JPN":"すぐに治まるはずですから、あまり心配しないでー","ENG":"It will calm down soon, so don't worry and–","TWN":"很快就會平靜下來的，不用太擔心……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"…말을 아끼겠습니다. 제가 한 건 아니지만 죄를 진 기분이군요.","JPN":"……言葉を惜しみましょう。僕の所業ではなくとも、罪を犯したような気分です。","ENG":"...I shouldn't jinx it. I feel somehow guilty for that.","TWN":"……我就不烏鴉嘴了。雖然不是我做的，但總感覺有些愧疚。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그렇지만 그라운드 원 한복판에서 대체 누가 이런 짓을?","JPN":"でも、グラウンド・ワンのど真ん中でいったい誰がこんなことを？","ENG":"But who would do that in the middle of Ground One?","TWN":"呃，不過到底是誰會在G1中心幹這種事？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIBBON_DEBT_NPC_NULL","text":{"KOREA":"찾-았-다.","JPN":"みーつーけーた。","ENG":"Found you.","TWN":"找——到——了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이… 이 트라우마를 자극하는 낯익은 목소리는…….","JPN":"こ……この、トラウマを刺激する聞きなれた声は……","ENG":"T-this trauma-triggering voice is...","TWN":"這……這個讓人害怕的熟悉聲音是……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그렇습니다. 동료애가 넘치는 자상한 크레데레입니다.","JPN":"そうです。仲間愛の溢れる優しいクレデレです。","ENG":"Yes. It is Credere, the kind and the compassionate.","TWN":"沒錯，是充滿同伴情誼的溫柔克蕾妲莉！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"늦어서 죄송합니다, 유피. 이것저것 처리하느라 조금 늦었습니다.","JPN":"遅れてすみません、ユピ。あれこれ処理していて、ちょっと遅くなりました。","ENG":"Sorry for the delay, Yuppie. It took a while to take care of some things.","TWN":"對不起，悠菲。處理其他事情耽誤了一點時間。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레? 여긴 어떻게 온 거예요?","JPN":"クレデレ？　ここにはどうやって来たんですか？","ENG":"Credere? How did you get here?","TWN":"克蕾妲莉？你怎麼會來這裡？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피에게 사과하러 왔습니다.","JPN":"ユピに謝りに来ました。","ENG":"Credere is here to apologize to you.","TWN":"克蕾妲莉來向悠菲道歉。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레가 의도한 건 아니지만 큰 폐를 끼쳤어요.","JPN":"クレデレは意図していなかったんですけど、大変ご迷惑をおかけして。","ENG":"Credere didn't intend it, but Credere was a nuisance.","TWN":"雖然並不是有意的，但還是給悠菲添了大麻煩。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"고작 그런 것 때문에 몰래 숨어든 거예요? 여긴 수용소라고요!","JPN":"そんなことのためにこっそり忍び込んだんですか？　ここは収容所ですよ！","ENG":"That's why you sneaked in here? This is prison!","TWN":"就因為這種事溜進來？這裡可是收容所啊！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"전 괜찮으니까 돌아가세요. 수용소에 뭔가 문제가 생긴 것 같다고요.","JPN":"私は大丈夫ですから、帰ってください。収容所に何か問題が起こったみたいです。","ENG":"I'm okay, so go back. There seems to be something going on here.","TWN":"我沒事，你們快回去吧。收容所好像出了什麼問題。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"안 됩니다. 크레데레는 유피에게 사과해야 합니다.","JPN":"ダメです。クレデレはユピに謝らないといけません。","ENG":"No. Credere has to apologize to Yuppie.","TWN":"不行，克蕾妲莉必須向悠菲道歉。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말 괜찮다니까요? 얘기라면 다음에 해도 충분하잖아요.","JPN":"本当に大丈夫ですってば。話なら今度すればいいでしょう？","ENG":"I'm really fine. We can talk later.","TWN":"真的沒關係啦？有什麼話以後再說吧？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피가 어디 있는지 몰라서 감방을 죄다 부숴버렸습니다.","JPN":"ユピがどこにいるのかわからなくて、監房を全部壊しました。","ENG":"Credere destroyed all the cells because Credere didn't know where Yuppie was.","TWN":"克蕾妲莉不知道悠菲在哪裡，所以把牢房全都敲開了。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"대탈출쇼가 졸지에 대탈옥쇼가 되어버렸어요.","JPN":"大脱出ショーが、大脱獄ショーになっちゃいました。","ENG":"The great escape plan became the great prison break plan.","TWN":"本來是要救你出去的，結果變成越獄風雲。"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"끼야하-! 자유다!!","JPN":"キャッハー！　自由だ！！","ENG":"Hahaha! We're free!","TWN":"哈哈哈哈——！自由了！！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};